import re

_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}
_TOKEN_RE = re.compile(r"^[A-Z0-9]+$")


def _split_fluxon_payload(payload: str) -> list[str]:
    if payload == "":
        return []
    return payload.split("-")


def _token_value(token: str) -> int:
    total = 0
    for ch in token:
        if "A" <= ch <= "Z":
            total += ord(ch) - ord("A") + 1
        elif "0" <= ch <= "9":
            total += ord(ch) - ord("0")
        else:
            raise ValueError(f"Invalid token character: {ch!r}")
    return len(token) * total


def solve(packet: str) -> int:
    parts = packet.split("::")
    if len(parts) != 5 or parts[0] != "FXN":
        raise ValueError(f"Invalid Fluxon packet format: {packet!r}")

    version = int(parts[1])
    payload = parts[3]

    if version not in _CHECKSUM_MODULUS:
        raise ValueError(f"Invalid version: {version}")

    tokens = _split_fluxon_payload(payload)
    for token in tokens:
        if not _TOKEN_RE.fullmatch(token):
            raise ValueError(f"Invalid token in payload: {token!r}")

    return sum(_token_value(token) for token in tokens) % _CHECKSUM_MODULUS[version]

