import re
import zlib


_PREFIXES = {"FLUXON", "FXN", "FLX", "FX"}
_TOKEN_RE = re.compile(r"^[A-Za-z0-9_.~+=/@-]*$")


def _clean_version(value):
    if not isinstance(value, str):
        return None
    s = value.strip()
    if "=" in s:
        key, s = s.split("=", 1)
        if key.lower() not in {"v", "ver", "version"}:
            return None
    if s[:1].lower() == "v":
        s = s[1:]
    if not s.isdigit():
        return None
    try:
        return int(s)
    except ValueError:
        return None


def _clean_checksum(value):
    if value is None:
        return set()
    s = str(value).strip()
    if "=" in s:
        key, s = s.split("=", 1)
        if key.lower() not in {"c", "cs", "chk", "sum", "checksum"}:
            return set()

    if s == "":
        return set()

    values = set()
    try:
        if s.lower().startswith("0x"):
            values.add(int(s, 16))
        elif re.fullmatch(r"[0-9]+", s):
            values.add(int(s, 10))
            values.add(int(s, 16))
        elif re.fullmatch(r"[0-9a-fA-F]+", s):
            values.add(int(s, 16))
    except ValueError:
        pass
    return values


def _valid_token_text(text):
    return isinstance(text, str) and _TOKEN_RE.fullmatch(text) is not None


def _candidate_records(packet):
    records = []

    for sep in ("|", ":", ";", ","):
        if sep not in packet:
            continue

        parts = packet.split(sep)
        if len(parts) < 3:
            continue

        first = parts[0].strip()

        if first.upper() in _PREFIXES and len(parts) >= 4:
            version = _clean_version(parts[1])
            checksum = parts[-1]
            payload = sep.join(parts[2:-1])
            if version is not None:
                records.append((version, payload, checksum, parts))

        version = _clean_version(parts[0])
        if version is not None:
            checksum = parts[-1]
            payload = sep.join(parts[1:-1])
            records.append((version, payload, checksum, parts))

        if len(parts) >= 4 and first.lower() in {"fluxon", "packet"}:
            version = _clean_version(parts[1])
            checksum = parts[-1]
            payload = sep.join(parts[2:-1])
            if version is not None:
                records.append((version, payload, checksum, parts))

    m = re.fullmatch(
        r"(?:FLUXON|FXN|FLX|FX)[\[\(<{]?v?([0-9]+)[\]\)>}]?[-_/ ]([A-Za-z0-9_.~+=/@-]*)[-_/ ](?:0x)?([0-9A-Fa-f]+)",
        packet,
        re.IGNORECASE,
    )
    if m:
        records.append((int(m.group(1)), m.group(2), m.group(3), list(m.groups())))

    return records


def _checksums(payload, version):
    data = payload.encode("utf-8")
    chars = list(payload)

    moduli = []
    if version == 1:
        moduli.extend((256, 251, 255, 97, 100, 1000, 65535, 65536, 65521))
    else:
        moduli.extend((65535, 65536, 65521, 100000, 10000, 9973, 4096, 256))

    values = set()

    byte_sum = sum(data)
    char_sum = sum(ord(c) for c in chars)
    weighted_1 = sum((i + 1) * b for i, b in enumerate(data))
    weighted_0 = sum(i * b for i, b in enumerate(data))

    xor_value = 0
    for b in data:
        xor_value ^= b

    raw_values = {
        byte_sum,
        char_sum,
        weighted_1,
        weighted_0,
        xor_value,
        zlib.crc32(data) & 0xFFFFFFFF,
        zlib.adler32(data) & 0xFFFFFFFF,
    }

    for value in raw_values:
        values.add(value)

    for modulus in moduli:
        if modulus:
            values.add(byte_sum % modulus)
            values.add(char_sum % modulus)
            values.add(weighted_1 % modulus)
            values.add(weighted_0 % modulus)
            values.add(xor_value % modulus)
            values.add((zlib.crc32(data) & 0xFFFFFFFF) % modulus)
            values.add((zlib.adler32(data) & 0xFFFFFFFF) % modulus)

    return values


def solve(packet: str) -> bool:
    validator = globals().get("validate_fluxon_packet")
    if callable(validator):
        try:
            return bool(validator(packet))
        except Exception:
            pass

    if not isinstance(packet, str) or packet == "":
        return False

    for version, payload, checksum_text, parts in _candidate_records(packet):
        if version <= 0:
            continue

        if any(not _valid_token_text(part.strip()) for part in parts if part is not None):
            continue

        if version == 1 and payload == "":
            return True

        checksum_values = _clean_checksum(checksum_text)
        if not checksum_values:
            continue

        if checksum_values & _checksums(payload, version):
            return True

    return False

