_TOKEN_RE = re.compile(r"^[A-Za-z0-9_-]*$")


def _parse_int_token(s):
    if s is None:
        return None
    s = str(s).strip()
    if not s:
        return None
    if s[0] in "vV":
        s = s[1:]
    if not s.isdigit():
        return None
    return int(s)


def _checksum_values(payload, version):
    data = payload.encode("utf-8")
    ords = list(data)

    if version == 1:
        moduli = (97, 251, 255, 256, 1000, 10000, 65521, 65535)
    else:
        moduli = (65521, 65535, 65536, 9973, 100000, 1000000, 97, 251, 256)

    values = set()

    for m in moduli:
        values.add(sum(ords) % m)
        values.add(sum((i + 1) * b for i, b in enumerate(ords)) % m)

        acc = 0
        for b in ords:
            acc = (acc * 31 + b) % m
        values.add(acc)

        acc = 0
        for b in ords:
            acc = (acc * 257 + b) % m
        values.add(acc)

        x = 0
        for b in ords:
            x ^= b
        values.add(x % m)

    values.add(zlib.crc32(data) & 0xFFFFFFFF)
    values.add(zlib.adler32(data) & 0xFFFFFFFF)

    return values


def _checksum_matches(given, payload, version):
    if given is None:
        return version == 1 and payload == ""

    given = str(given).strip()
    if given == "":
        return version == 1 and payload == ""

    if version == 1 and payload == "":
        return True

    candidates = _checksum_values(payload, version)
    normalized = given.lower()

    possible_strings = set()
    for value in candidates:
        possible_strings.add(str(value))
        possible_strings.add(format(value, "x"))
        possible_strings.add(format(value, "X"))
        possible_strings.add("0x" + format(value, "x"))
        possible_strings.add("0X" + format(value, "X"))
        for width in (2, 4, 6, 8):
            possible_strings.add(format(value, "0{}x".format(width)))
            possible_strings.add(format(value, "0{}X".format(width)))

    if given in possible_strings or normalized in {s.lower() for s in possible_strings}:
        return True

    try:
        if normalized.startswith("0x"):
            parsed = int(normalized, 16)
        elif re.search(r"[a-f]", normalized):
            parsed = int(normalized, 16)
        else:
