                payload = kv[k]
                break
        checksum = None
        for k in ("checksum", "check", "sum", "crc", "cs", "c"):
            if k in kv:
                checksum = kv[k]
                break
        if version is not None and payload is not None:
            yield version, payload, checksum

    for delim in ("|", ":", ";", ","):
        if delim not in p:
            continue
        parts = p.split(delim)
        if len(parts) < 2:
            continue

        first = parts[0].strip()
        prefixes = {"FLUXON", "FXN", "FLX", "F"}

        if first.upper() in prefixes and len(parts) >= 3:
            version = _parse_int_token(parts[1])
            if version is not None:
                if len(parts) >= 4:
                    yield version, delim.join(parts[2:-1]), parts[-1]
