                yield version, "", None

    m = re.fullmatch(r"\s*[vV]?(\d+)\s+(\S*)\s+(\S+)\s*", p)
    if m:
        yield int(m.group(1)), m.group(2), m.group(3)


def solve(packet: str) -> bool:
    validator = globals().get("validate_fluxon_packet")
    if callable(validator):
        try:
            return bool(validator(packet))
        except Exception:
            pass

    if not isinstance(packet, str):
        return False

    seen = set()
    for version, payload, checksum in _records(packet):
        key = (version, payload, checksum)
        if key in seen:
            continue
        seen.add(key)

