            continue
        if not _payload_shape_ok(payload):
            continue
        if checksum is not None and not re.fullmatch(r"[A-Za-z0-9xX+-]*", str(checksum).strip()):
            continue
        if _checksum_matches(checksum, payload, version):
            return True

    return False

