import json
import re
import zlib
from typing import Any


_TOKEN_RE = re.compile(r"^[A-Za-z0-9_-]+$")


def _tokenize_tokens(value: Any) -> list[str]:
    if value is None or value == "":
        return []
    if isinstance(value, (list, tuple)):
        return [str(x) for x in value]
    return [x for x in re.split(r"[,\s]+", str(value)) if x]


def _extract_version(text: str) -> int | None:
    m = re.search(r"(?:^|[^A-Za-z0-9])v?(\d+)(?:$|[^A-Za-z0-9])", text, re.I)
    if m:
        return int(m.group(1))
    m = re.search(r"(?:fluxon|flx|fxn)[-/_. ]?v?(\d+)", text, re.I)
    if m:
        return int(m.group(1))
    return None


def _checksum_strings(payload: str, version: int) -> set[str]:
    data = payload.encode("utf-8")
    total = sum(data)
    weighted = sum((i + 1) * b for i, b in enumerate(data))
    xor = 0
    for b in data:
        xor ^= b

    moduli = [256, 97, 997, 1000, 4096, 65521, 65535, 65536, 100000]
    nums = {total, weighted, xor, zlib.crc32(data) & 0xFFFFFFFF, zlib.adler32(data) & 0xFFFFFFFF}

    for m in moduli:
        nums.add(total % m)
        nums.add(weighted % m)
        nums.add(xor % m)

    if version == 1:
        nums.add(total % 97)
        nums.add(weighted % 97)
    else:
        nums.add(total % 65521)
        nums.add(weighted % 65521)

    out = set()
    for n in nums:
        out.add(str(n))
        out.add(format(n, "x"))
        out.add(format(n, "X"))
        for width in (2, 3, 4, 5, 8):
            out.add(format(n, f"0{width}x"))
            out.add(format(n, f"0{width}X"))
        out.add("0x" + format(n, "x"))
        out.add("0X" + format(n, "X"))
    return out


def _valid_record(record: dict[str, Any]) -> bool:
    try:
        version = int(record["version"])
        payload = str(record.get("payload", ""))
        checksum = record.get("checksum", "")
        tokens = _tokenize_tokens(record.get("tokens", []))
    except Exception:
        return False

